229	  Future<void> _fetchData() async {
230	    try {
231	      final token = await _getToken();
232	      if (token == null) {
233	        setState(() {
234	          _error = 'Not logged in';
235	          _loading = false;
236	        });
237	        return;
238	      }
239	      final headers = {'Authorization': 'Bearer $token'};
240	
241	      final results = await Future.wait([
242	        http.get(Uri.parse('$_baseUrl/api/users/me'), headers: headers),
243	        http.get(Uri.parse('$_baseUrl/api/who_likes_me'), headers: headers),
244	        http.get(Uri.parse('$_baseUrl/api/rank-one-status'), headers: headers),
245	      ]);
246	
247	      final meRes = results[0];
248	      final res = results[1];
249	      final lockRes = results[2];
250	
251	      if (meRes.statusCode == 200) {
252	        _currentUserId = (json.decode(meRes.body))['id'] as int?;
253	      }
254	
255	      _IncomingLockInfo? incomingLock;
256	      if (lockRes.statusCode == 200) {
257	        try {
