264	      }
265	
266	      if (res.statusCode == 200) {
267	        try {
268	          final data = json.decode(res.body);
269	          debugPrint('[WhoLikesMe] Raw response: ${res.body.substring(0, res.body.length > 500 ? 500 : res.body.length)}');
270	          final List<dynamic> users = data['users'] ?? [];
271	          debugPrint('[WhoLikesMe] Parsed ${users.length} users from API');
272	          final parsed = users
273	              .map((u) => _WhoLikesMeEntry.fromJson(u as Map<String, dynamic>))
274	              .toList();
275	          debugPrint('[WhoLikesMe] Created ${parsed.length} entry objects');
276	          setState(() {
277	            _entries = parsed;
278	            _incomingLock = incomingLock;
279	            _loading = false;
280	          });
281	          debugPrint('[WhoLikesMe] State updated with ${_entries.length} entries, incomingLock=${incomingLock != null}');
282	        } catch (e, stackTrace) {
283	          debugPrint('[WhoLikesMe] Parse error: $e');
284	          debugPrint('[WhoLikesMe] Stack: $stackTrace');
285	          setState(() {
286	            _error = 'Parse error: $e';
287	            _loading = false;
288	          });
289	        }
290	      } else {
291	        setState(() {
292	          _error = 'Failed (${res.statusCode})';
293	          _loading = false;
294	        });
295	      }
296	    } catch (e) {
297	      setState(() {
298	        _error = 'Error: $e';
299	        _loading = false;
300	      });
301	    }
302	  }
