304	  Future<void> _connectWebSocket() async {
305	    if (_currentUserId == null) return;
306	    final token = await _getToken();
307	    if (token == null) return;
308	    try {
309	      final uri = Uri.parse('$_wsUrl/api/ws/rank_updates/$_currentUserId');
310	      _wsChannel = WebSocketChannel.connect(uri);
