312	        (message) => _handleWsMessage(message as String),
313	        onError: (e) => debugPrint('[WhoLikesMe WS] error: $e'),
314	        onDone: () => debugPrint('[WhoLikesMe WS] closed'),
315	      );
316	      debugPrint('[WhoLikesMe WS] connected for user $_currentUserId');
