322	  void _handleWsMessage(String raw) {
323	    try {
324	      final data = json.decode(raw) as Map<String, dynamic>;
325	      if (data['type'] == 'rank_update') {
326	        final fromUsername = data['from_username'] as String?;
327	        final newRank = data['new_rank'] as int?;
328	        if (fromUsername == null || newRank == null) return;
329	        setState(() {
330	          final idx =
331	              _entries.indexWhere((e) => e.username == fromUsername);
332	          if (idx != -1) _entries[idx].theirRankOfMe = newRank;
333	        });
334	      } else if (data['type'] == 'lock_update' || data['event'] == 'wlm_changed') {
335	        // Refresh the entire list when locks change
336	        _fetchData();
337	      }
338	    } catch (_) {}
339	  }
