174	  void _onWilClosed() {
175	    _wsSetConnected(false);
176	    _closeWilChannel();
177	    if (_disposed) return;
178	    // Try to reconnect with exponential-ish backoff (capped).
179	    _wsReconnectAttempts++;
180	    final delaySeconds = (_wsReconnectAttempts * 2).clamp(2, 30);
181	    _wsReconnectTimer?.cancel();
182	    _wsReconnectTimer = Timer(Duration(seconds: delaySeconds), () {
183	      if (!_disposed) _connectWil();
184	    });
